function processApplyDefaultCustomerToggled(e) {
  const $toggle = $(this);
  if ($toggle.is(":checked")) {
    return
  }
  const $errorDiv = $toggle.parent(".toggle").siblings("div.text-danger-wrapper");
  if ($errorDiv.length) {
    $errorDiv.remove();
  }
  const $linkLabel = $toggle.parent(".toggle").siblings('a.label-purple-info');
  if ($linkLabel.is(':visible')) {

    $toggle.bootstrapToggle('on');
    let $link = $toggle.parent(".toggle").siblings('a.label-purple-info');
    $link.after(`
    <div class='text-danger-wrapper'>
      <label class='text-danger'>This feature is available on higher plans. <a target="_blank" href="/organizations/billing?action=UPGRADE">Upgrade plan</a></label>
    </div>
    `);
  }
}

