function initInventorySettings(settingsTabWrapper) {
  settingsTabWrapper.find("input[type='checkbox'].toggle-checkbox").bootstrapToggle();
  let manageInventoryToggle = getElement('inventory-settings-manage-inventory', 'default.');

  manageInventoryToggle.bootstrapToggle().change(function (e) {
    var $toggle = $(this);
    var $errorLabel = $toggle.parent(".toggle").siblings("label.text-danger");
    if ($errorLabel.length) {
      $errorLabel.remove();
    }
    if (!$toggle.is(":checked")) {
      return
    }
    let $upgradeLabel = getElement('inventory-management-upgrade-link', 'default.');
    // First check: is inventory management allowed by subscription(purple label)
    if ($upgradeLabel.is(':visible')) {

      $toggle.bootstrapToggle('off');
      let $link = $toggle.parent(".toggle").siblings('a.label-purple-info');
      $link.after(`
      <label class='text-danger'>This feature is available on higher plans. <a target="_blank" href="/organizations/billing?action=UPGRADE">Upgrade plan</a></label>
    `);
    }
  });

  manageInventoryToggle.change(function () {
    let additionalSettingsWrapper = settingsTabWrapper.find('.inventory-management-additional-settings');
    if ($(this).is(':checked')) {
      showWarningModal();
      additionalSettingsWrapper.removeClass('hidden');
      getElement('apply-default-item', 'default.').val('off');
    } else {
      additionalSettingsWrapper.addClass('hidden');
    }
  });
}

