function processInventoryManagementVisibility() {
  let $manageInventoryToggle = getElement('inventory-settings-manage-inventory', "default.");
  let $inventorySettingsContainer = getElement('inventory-settings-container', "default.");
  let $defaultProductConfig = getElement('default-product-configuration', "default.");
  if ($manageInventoryToggle.prop("checked")) {
    $defaultProductConfig.hide();
    $inventorySettingsContainer.show();
  } else {
    $defaultProductConfig.show();
  }
}

