function setupPopovers() {
  var $wrapper = getElement("tax-settings-tab-wrapper", "default.");
  setupGeneralPopovers($wrapper);
  setupGenericTaxPopovers($wrapper);
}

function setupGeneralPopovers($wrapper) {
  [
    {labelClass: 'apply-taxes', message: 'If "On", system tries to find a tax code and apply it, otherwise a tax amount is included in total amount only.'},
    {
      labelClass: 'sales-apply-generic',
      message: "This setting allows you to change existing tax info in the transaction, or apply tax if the original transaction does not contain it."
    },
    {
      labelClass: 'expense-apply-generic',
      message: "This setting allows you to change existing tax info in the transaction, or apply tax if the original transaction does not contain it."
    },
    {
      labelClass: 'tax-withheld-line-account',
      message: "This setting allows you to specify an account to which marketplace facilitator taxes will be applied."
    }
  ].forEach(function (popoverParams) {
    $wrapper.find('label.control-label.' + popoverParams.labelClass).popover({
      content: popoverParams.message,
      placement: "top",
      trigger: 'hover',
      container: "body",
      html: true
    });
  });
}

function setupGenericTaxPopovers($wrapper) {
  [
    {
      identifierClass: 'WITH_TAX',
      message: "If the original transaction in your payment processor contains tax info, this setting allows changing the tax amount for a different one"
    },
    {
      identifierClass: 'WITHOUT_TAX',
      message: "If the original transaction in your payment processor does not contain tax info, this setting allows applying tax in accordance with your preference"
    },
    {
      identifierClass: 'EXPENSE',
      message: "Purchases made via your payment processor."
    },
    {
      identifierClass: 'FEE',
      message: "Type of transaction that app creates in your accounting system to reflect the fee paid to payment processor."
    },
    {
      identifierClass: 'APPLICATION_FEE',
      message: "Type of transaction that app creates in your accounting system to reflect the fee paid to third-party application that processed the transaction."
    },
    {
      identifierClass: 'FEE_REFUND',
      message: "Type of transaction that app creates in your accounting system to reflect the refund of the fee that was taken by the payment processor."
    },
    {
      identifierClass: 'APPLICATION_FEE_REFUND',
      message: "Type of transaction that app creates in your accounting system to reflect the refund of the fee paid to third-party application that processed the transaction."
    },
    {
      identifierClass: 'SHIPPING',
      message: "If the original transaction contains information about shipping."
    },
  ].forEach(function (popoverParams) {
    $wrapper.find('span.input-group-addon.' + popoverParams.identifierClass).popover({
      content: popoverParams.message,
      placement: "top",
      trigger: 'hover',
      container: "body",
      html: true
    });
  });
}
